-- supabase_schema.sql
-- 工場点検管理システム Supabase スキーマ定義
-- 生成日: 2026-05-19

-- ============================================================
-- 1. DROP TABLE (IF EXISTS)
-- ============================================================
DROP TABLE IF EXISTS inspection_results CASCADE;
DROP TABLE IF EXISTS inspection_items CASCADE;
DROP TABLE IF EXISTS equipment CASCADE;
DROP TABLE IF EXISTS rooms CASCADE;
DROP TABLE IF EXISTS factories CASCADE;

-- ============================================================
-- 2. CREATE TABLE
-- ============================================================
CREATE TABLE factories (
  id integer PRIMARY KEY,
  name text NOT NULL
);

CREATE TABLE rooms (
  id integer PRIMARY KEY,
  factory_id integer REFERENCES factories(id),
  name text NOT NULL
);

CREATE TABLE equipment (
  id integer PRIMARY KEY,
  room_id integer REFERENCES rooms(id),
  name text NOT NULL,
  inspection_cycle_years integer NOT NULL DEFAULT 1,
  last_inspected_at date
);

CREATE TABLE inspection_items (
  id integer PRIMARY KEY,
  equipment_id integer REFERENCES equipment(id),
  item_name text NOT NULL
);

CREATE TABLE inspection_results (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  inspection_item_id integer REFERENCES inspection_items(id),
  equipment_id integer REFERENCES equipment(id),
  room_id integer REFERENCES rooms(id),
  factory_id integer REFERENCES factories(id),
  record_type text NOT NULL DEFAULT 'inspection',
  result text,
  comment text,
  confirmed_at timestamptz,
  inspected_at timestamp DEFAULT now(),
  updated_at timestamp DEFAULT now(),
  UNIQUE(inspection_item_id)
);

